(window.webpackJsonp=window.webpackJsonp||[]).push([[449],{1076:function(n,r){n.exports="\x3c!-- \r\ntitle: 22-JS结构\r\nsort: \r\n--\x3e \r\n# JS内置函数\r\n\r\n## 内置函数\r\n\r\n- typeof\r\n\r\n  > 检测变量操作类型\r\n\r\n- null\r\n\r\n  > 清空对象\r\n  >\r\n  > ```js\r\n  > var person = null;           // 值为 null(空), 但类型为对象\r\n  > var person = undefined;     // 值为 undefined, 类型为 undefined\r\n  > ```\r\n\r\n## 类型转换\r\n\r\n> 在 JavaScript 中有 6 种不同的数据类型：\r\n>\r\n> - string\r\n> - number\r\n> - boolean\r\n> - object\r\n> - function\r\n> - symbol\r\n>\r\n> 3 种对象类型：\r\n>\r\n> - Object\r\n> - Date\r\n> - Array\r\n>\r\n> 2 个不包含任何值的数据类型：\r\n>\r\n> - null\r\n> - undefined\r\n\r\n`constructor`\r\n\r\n> 返回变量的构造函数\r\n>\r\n> ```js\r\n> \"John\".constructor                 // 返回函数 String()  { [native code] }\r\n> (3.14).constructor                 // 返回函数 Number()  { [native code] }\r\n> false.constructor                  // 返回函数 Boolean() { [native code] }\r\n> [1,2,3,4].constructor              // 返回函数 Array()   { [native code] }\r\n> {name:'John', age:34}.constructor  // 返回函数 Object()  { [native code] }\r\n> new Date().constructor             // 返回函数 Date()    { [native code] }\r\n> function () {}.constructor         // 返回函数 Function(){ [native code] }\r\n> ```\r\n>\r\n> 判断对象类型\r\n>\r\n> `Array.constructor.toString().indexOf(\"Array\") > -1`\r\n\r\n`String()`\r\n\r\n> 将各种类型转为字符串：\r\n>\r\n> `.toString()`\r\n>\r\n> `String(new Date())`\r\n\r\n`Number()`\r\n\r\n> 将字符串转为数字\r\n\r\n## Map与Set\r\n\r\n> {}的键必须为字符串，Map解决了这个问题\r\n>\r\n> map 为键值对结构，查找速度极快\r\n>\r\n> set 类似python元组，元素不能重复\r\n\r\n```js\r\n// 创建map\r\nvar m = new Map([['fzf','83'],['nmd',17],['doge',16]]);\r\nm.delete('fzf');\r\nm.set('fzf',19);\r\nconsole.log(m.get('fzf'));\r\n// set\r\nvar s = new Set([1,1,2,3,5]);\r\nconsole.log([...s])\r\n```\r\n\r\n## 迭代\r\n\r\n> 迭代类型可以通过`for..of`来遍历\r\n\r\n```js\r\nvar a = ['A', 'B', 'C'];\r\nvar s = new Set(['A', 'B', 'C']);\r\nvar m = new Map([[1, 'x'], [2, 'y'], [3, 'z']]);\r\nfor (var x of a) { // 遍历Array\r\n    console.log(x);\r\n}\r\nfor (var x of s) { // 遍历Set\r\n    console.log(x);\r\n}\r\nfor (var x of m) { // 遍历Map\r\n    console.log(x[0] + '=' + x[1]);\r\n}\r\n```\r\n\r\n\r\n\r\n"}}]);